def showImg(name, path):
    cv.namedWindow(name)
    # Construct absolute path relative to script directory
    img = cv.imread(os.path.join(SCRIPT_DIR, path))
    cv.imshow(name, img)
    cv.waitKey()
    cv.destroyAllWindows()
    return "ok"

