    def updatetable(self, table, total_rows, variable, Description, value, ref):
        for i in range(total_rows):
            if i < len(ref):
                table.setItem(i, 0, QtWidgets.QTableWidgetItem(variable[i]))
                table.setItem(i, 1, QtWidgets.QTableWidgetItem(Description[i]))

                table.setItem(i, 3, QtWidgets.QTableWidgetItem(ref[i]))

                try:
                    table.setItem(i, 2, QtWidgets.QTableWidgetItem(str(round(value[i],3))))
                except:
                    table.setItem(i, 2, QtWidgets.QTableWidgetItem(str(value[i])))




            else:
                table.setItem(i, 0, QtWidgets.QTableWidgetItem(""))
                table.setItem(i, 1, QtWidgets.QTableWidgetItem(""))
                table.setItem(i, 2, QtWidgets.QTableWidgetItem(""))
                table.setItem(i, 3, QtWidgets.QTableWidgetItem(""))

    def step1(self):
        if self.checkBox_s1.isChecked():
            try:
                df['sigma_x_max'] = float(self.sigma_x_max.text())
                df['sigma_x_min'] = float(self.sigma_x_min.text())
                df['sigma_y_max'] = float(self.sigma_y_max.text())
                df['sigma_y_min'] = float(self.sigma_y_min.text())
                df['t_max'] = float(self.t_max.text())
                df['t_min'] = float(self.t_min.text())
                df['sigma_m_x'] = 0.5 * (df['sigma_x_max'] + df['sigma_x_min'])
                df['sigma_a_x'] = 0.5 * (df['sigma_x_max'] - df['sigma_x_min'])
                df['sigma_m_y'] = 0.5 * (df['sigma_y_max'] + df['sigma_y_min'])
                df['sigma_a_y'] = 0.5 * (df['sigma_y_max'] - df['sigma_y_min'])

                df['t_m'] = 0.5 * (df['t_max'] + df['t_min'])
                df['t_a'] = 0.5 * (df['t_max'] - df['t_min'])
                df['Rx'] = get_R(df['sigma_m_x'], df['sigma_a_x'])
                df['Ry'] = get_R(df['sigma_m_y'], df['sigma_a_y'])
                df['Rt'] = get_R(df['t_m'], df['t_a'])

                variable = ['σx_max', 'σx_min', 'σy_max', 'σy_min', 't_max', 't_min', 'σx_m', 'σy_m', 't_m', 'σx_a', 'σy_a', 't_a', 'Rx', 'Ry', 'Rt']
                Description = ['X Normal Stress Max', 'X Normal Stress Min', 'Y Normal Stress Max', 'Y Normal Stress Min', 'Shear Stress Max', 'Shear Stress Min', 'Mean Stress X', 'Mean Stress Y', 'Mean Stress Shear', 'Stress Amplitude X', 'Stress Amplitude Y', 'Shear Stress Amplitude', 'Stress Ratio X', 'Stress Ratio Y', 'Shear Stress Ratio']
                value = [df['sigma_x_max'], df['sigma_x_min'], df['sigma_y_max'], df['sigma_y_min'], df['t_max'], df['t_min'],  df['sigma_m_x'],  df['sigma_m_y'],  df['t_m'], df['sigma_a_x'],  df['sigma_a_y'],  df['t_a'], df['Rx'], df['Ry'], df['Rt']]
                ref = ['calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation','calculation','calculation','calculation','calculation','calculation','calculation',]

                self.updatetable(self.table1, 30, variable, Description, value, ref)

                self.data1['Variable'] = variable
                self.data1['Description'] = Description
                self.data1['Value'] = value
                self.data1['Reference'] = ref
            except Exception as e:
                print (e)

    def step1_w(self):
        if self.checkBox_s1w.isChecked():
            try:

                df['sigma_pp_max'] = float(self.sigma_pp_max.text())
                df['sigma_pp_min'] = float(self.sigma_pp_min.text())
                df['sigma_pl_max'] = float(self.sigma_pl_max.text())
                df['sigma_pl_min'] = float(self.sigma_pl_min.text())
                df['t_pl_max'] = float(self.t_pl_max.text())
                df['t_pl_min'] = float(self.t_pl_min.text())


                df['sigma_m_n'] = 0.5 * (df['sigma_pp_max'] + df['sigma_pp_min'])
                df['sigma_a_n'] = 0.5 * (df['sigma_pp_max'] - df['sigma_pp_min'])
                df['sigma_m_1'] = 0.5 * (df['sigma_pl_max'] + df['sigma_pl_min'])
                df['sigma_a_1'] = 0.5 * (df['sigma_pl_max'] - df['sigma_pl_min'])
                df['t_m_1'] = 0.5 * (df['t_pl_max'] + df['t_pl_min'])
                df['t_a_1'] = 0.5 * (df['t_pl_max'] - df['t_pl_min'])

                if (df['sigma_m_n'] + df['sigma_a_n']) == 0:
                    df['R_pp'] = 0
                else:
                    df['R_pp'] = (df['sigma_m_n'] - df['sigma_a_n']) / (df['sigma_m_n'] + df['sigma_a_n'])

                if (df['sigma_m_1'] + df['sigma_a_1']) == 0:
                    df['R_pl'] = 0
                else:
                    df['R_pl'] = (df['sigma_m_1'] - df['sigma_a_1']) / (df['sigma_m_1'] + df['sigma_a_1'])
                if (df['t_m_1'] + df['t_a_1']) == 0:
                    df['R_t'] = 0
                else:
                    df['R_t'] = (df['t_m_1'] - df['t_a_1']) / (df['t_m_1'] + df['t_a_1'])


                variable = ['σ⊥_max', 'σn_min', 'σ∥_max', 'σ∥_min', 't_max', 't_min', 'σ⊥_m', 'σ∥_m', 't_m', 'σ⊥_a', 'σ∥_a', 't_a', 'Rn', 'Rl', 'Rt']
                Description = ['Stress Perpendicular to Welds Max', 'Stress Perpendicular to Welds Min', 'Stress Parallel to Welds Max', 'Stress Parallel to Welds Min', 'Shear Stress Max', 'Shear Stress Min', 'Mean Stress Perpendicular to Welds', 'Mean Stress Parallel to Welds', 'Mean Stress Shear', 'Perpendicular Stress Amplitude', 'Parallel Stress Amplitude', 'Shear Stress Amplitude', 'Perpendicular Stress Ratio', 'Parallel Stress Ratio', 'Shear Stress Ratio']
                value = [df['sigma_pp_max'], df['sigma_pp_min'], df['sigma_pl_max'], df['sigma_pp_min'], df['t_pl_max'], df['t_pl_min'],  df['sigma_m_n'],  df['sigma_m_1'],  df['t_m_1'], df['sigma_a_n'],  df['sigma_a_1'],  df['t_a_1'], df['R_pp'], df['R_pl'], df['R_t']]
                ref = ['calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation', 'calculation','calculation','calculation','calculation','calculation','calculation','calculation']

                self.updatetable(self.table1, 30, variable, Description, value, ref)
                self.data1_w['Variable'] = variable
                self.data1_w['Description'] = Description
                self.data1_w['Value'] = value
                self.data1_w['Reference'] = ref
            except Exception as e:
                print (e)

