    def step3(self):
        try:
            if self.checkBox_s3.isChecked():
                Kf = 2
                df['n_pl'] = 1  # per STD191010
                K_V = float(self.surface_treatment.text())
                K_S = 1
                K_NL_E = 1
                df['K_V'] = K_V
                df['K_S'] = K_S
                df['K_NL_E'] = 1

                variable = ['npl', 'Kf', 'Kv', 'Ks', 'KNL,E']
                Description = ['Section Factor', 'Fatigue Notch Factor', 'Surface Treatment Factor', 'Coating Factor', 'Factor for GJL']
                value = [1, 2, K_V, K_S, K_NL_E]
                if self.surface_treatment.text() == '1':
                    ref = ['per STD191010', 'Table 4.3.1', 'Table 4.3.7', '(4.3.29)', '(4.3.32)']
                else:
                    ref = ['per STD191010', 'Table 4.3.1', '(4.3.28)', '(4.3.29)', '(4.3.32)']

                if self.comboBox_kt_sel.currentIndex() == 1:
                    A_ref = 500
                    A_sigma = float(self.A_sigma.text())
                    n_st = (A_ref / A_sigma) ** (1 / 30)
                    n_ = 0.15  ## for steel

                    ds = float(self.ds.text())
                    sigma_1a = float(self.sigma_1a.text())
                    t_1a = float(self.t_1a.text())

                    sigma_2a = float(self.sigma_2a.text())
                    t_2a = float(self.t_2a.text())

                    G_s = abs( 1/ ds * (1 - (sigma_2a / sigma_1a)))
                    G_t = abs(1 / ds * (1 - (t_2a / t_1a)))
                    print(G_s)

                    n_vm = math.sqrt(1 + 210000 * 0.0002 / df['sigma_W_zd'] * (
                                n_st ** (1 / n_ - 1)))
                    print('n_vm')
                    n_bm_t = max(1, (5 + math.sqrt(G_t)) / (5 * n_vm * n_st + df['Rm'] / 680 * math.sqrt(
                        (7.5 + math.sqrt(G_t)) / 1 + 0.2 * math.sqrt(G_t))))
                    print('n_bm_t')
                    n_bm_s = max(1, (5 + math.sqrt(G_s)) / (5 * n_vm * n_st + df['Rm'] / 680 * math.sqrt(
                        (7.5 + math.sqrt(G_s)) / 1 + 0.2 * math.sqrt(G_s))))





                    n_sigma = n_st * n_vm * n_bm_s
                    n_t = n_st * n_vm * n_bm_t

                    self.appenditem(variable, ['n_st','n_vm', 'n_bm,σ', 'n_bm,t','nσ', 'nt'])
                    self.appenditem(Description, ['Statistical Kt-Kf Ratio', 'Deformation-Mechanical Kt-Kf Ratio',
                                        'Fracture-Mechanical Kt-Kf Ratio', 'Fracture-Mechanical Kt-Kf Ratio','Material-Mechanical Kt-Kf Ratio', 'Material-Mechanical Kt-Kf Ratio'])
                    self.appenditem(value, [n_st, n_vm, n_bm_s, n_bm_t, n_sigma, n_t])
                    self.appenditem(ref, ['(4.3.11)', '(4.3.14)', '(4.3.15)', '(4.3.15)', '(4.3.10)', '(4.3.10)'])
                else:
                    n_sigma = 1
                    n_t = 1
                    self.appenditem(variable, ['nσ', 'nt'])
                    self.appenditem(Description, ['Material-Mechanical Kt-Kf Ratio', 'Material-Mechanical Kt-Kf Ratio'])
                    self.appenditem(value, [n_sigma, n_t])
                    self.appenditem(ref, ['4.3.1.3', '4.3.1.3'])
                if str(self.roughness.text()) == '0':
                    K_R_sigma = 1
                    K_R_t = 1
                    self.appenditem(variable, ['KR,σ', 'KR,t'])
                    self.appenditem(Description,
                        ['Roughness Factor for Polished Component', 'Roughness Factor for Polished Component'])
                    self.appenditem(value, [1, 1])
                    self.appenditem(ref, ['(4.3.20)', '(4.3.20)'])
                else:
                    Rz = float(self.roughness.text())
                    K_R_sigma = 1 - 0.22 * math.log(Rz, 10) * math.log(2 * df['Rm'] / 400, 10)
                    K_R_t = 1 - df['fW_t'] * 0.22 * math.log(Rz, 10) * math.log(2 * df['Rm'] / 400, 10)

                    self.appenditem(variable, ['Rz', 'KR,σ', 'KR,t'])
                    self.appenditem(Description, ['Surface Roughness','Roughness Factor', 'Roughness Factor'])
                    self.appenditem(value, [Rz, K_R_sigma, K_R_t])
                    self.appenditem(ref, ['per design', '(4.3.21)', '(4.3.21)'])
                df['K_R_sigma'] = K_R_sigma
                df['K_R_t'] = K_R_t

                df['K_WK_sigma'] = 1 / n_sigma * (1 + 1 / Kf * (1 / K_R_sigma - 1)) / K_V / K_S / K_NL_E
                df['K_WK_t'] = 1 / n_t * (1 + 1 / Kf * (1 / K_R_t - 1)) / K_V / K_S

                self.appenditem(variable, ['Kwk,σ', 'Kwk,t'])
                self.appenditem(Description, [ 'Design Factor', 'Design Factor'])
                self.appenditem(value, [df['K_WK_sigma'], df['K_WK_t']])
                self.appenditem(ref, ['(4.3.1)', '(4.3.1)'])
                self.updatetable(self.table3, 30, variable, Description, value, ref)
                self.data3['Variable'] = variable
                self.data3['Description'] = Description
                self.data3['Value'] = value
                self.data3['Reference'] = ref

        except Exception as e:
            print (e)


